class TreasureHuntModel(BaseModel):
    hunt_id: str
    title: str
    description: str
    difficulty: str  # easy, medium, hard
    prc_cost: int
    reward_prc: int
    cashback_percentage: int = 50
    total_clues: int
    clue_cost: int = 5
    treasure_locations: List[Dict]
    time_limit_minutes: int
    active: bool = True
    created_at: str = Field(default_factory=lambda: datetime.now(timezone.utc).isoformat())

class UserTreasureProgress(BaseModel):
    progress_id: str
    user_id: str
    hunt_id: str
    started_at: str
    clues_revealed: List[int] = []
    attempts: int = 0
    found: bool = False
    found_at: Optional[str] = None
    prc_spent: int = 0
    cashback_earned: int = 0
    completed: bool = False

class StartHuntRequest(BaseModel):
    hunt_id: str

class BuyClueRequest(BaseModel):
    progress_id: str
    clue_number: int

class FindTreasureRequest(BaseModel):
    progress_id: str
    location_id: int

