@api_router.post("/admin/ledger/profit-loss-summary/generate")
async def generate_profit_loss_summary(request: Request):
    """Generate daily P&L summary for a date"""
    try:
        data = await request.json()
        date = data.get("date", datetime.now(timezone.utc).strftime("%Y-%m-%d"))
        
        ad_revenue = await db.ad_revenue_ledger.aggregate([
            {"$match": {"date": date}},
            {"$group": {"_id": None, "total": {"$sum": "$net_amount"}}}
        ]).to_list(1)
        
        subscription_income = await db.subscription_income_ledger.aggregate([
            {"$match": {"date": date, "status": "completed"}},
            {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
        ]).to_list(1)
        
        commission_income = await db.commission_income_ledger.aggregate([
            {"$match": {"date": date}},
            {"$group": {"_id": None, "total": {"$sum": "$net_commission"}}}
        ]).to_list(1)
        
        interest_income = await db.interest_income_ledger.aggregate([
            {"$match": {"date_received": date}},
            {"$group": {"_id": None, "total": {"$sum": "$interest_amount"}}}
        ]).to_list(1)
        
        penalty_income = await db.penalty_income_ledger.aggregate([
            {"$match": {"date": date}},
            {"$group": {"_id": None, "total": {"$sum": "$equivalent_inr"}}}
        ]).to_list(1)
        
        expenses = await db.expense_ledger.aggregate([
            {"$match": {"date": date}},
            {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
        ]).to_list(1)
        
        redeem_payouts = await db.redeem_payout_ledger.aggregate([
            {"$match": {"date": date, "status": "paid"}},
            {"$group": {"_id": None, "total": {"$sum": "$amount_inr"}}}
        ]).to_list(1)
        
        total_income = (
            (ad_revenue[0].get("total", 0) if ad_revenue else 0) +
            (subscription_income[0].get("total", 0) if subscription_income else 0) +
            (commission_income[0].get("total", 0) if commission_income else 0) +
            (interest_income[0].get("total", 0) if interest_income else 0) +
            (penalty_income[0].get("total", 0) if penalty_income else 0)
        )
        
        total_expense = (
            (expenses[0].get("total", 0) if expenses else 0) +
            (redeem_payouts[0].get("total", 0) if redeem_payouts else 0)
        )
        
        summary = {
            "date": date,
            "ad_revenue": ad_revenue[0].get("total", 0) if ad_revenue else 0,
            "subscription_income": subscription_income[0].get("total", 0) if subscription_income else 0,
            "commission_income": commission_income[0].get("total", 0) if commission_income else 0,
            "interest_income": interest_income[0].get("total", 0) if interest_income else 0,
            "penalty_income": penalty_income[0].get("total", 0) if penalty_income else 0,
            "total_income": total_income,
            "operational_expenses": expenses[0].get("total", 0) if expenses else 0,
            "redeem_payouts": redeem_payouts[0].get("total", 0) if redeem_payouts else 0,
            "total_expense": total_expense,
            "net_profit_loss": total_income - total_expense,
            "created_at": datetime.now(timezone.utc).isoformat()
        }
        
        await db.daily_profit_loss_summary.update_one(
            {"date": date},
            {"$set": summary},
            upsert=True
        )
        
        return {"success": True, "summary": summary}
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@api_router.get("/admin/ledger/balance-sheet")
async def get_balance_sheet():
    """Get auto-generated balance sheet"""
    try:
        settings = await db.settings.find_one({}, {"_id": 0, "accounting_settings": 1})
        prc_per_inr = settings.get("accounting_settings", {}).get("prc_per_inr", 10) if settings else 10
        
        cash_latest = await db.cash_ledger.find_one({}, {"_id": 0, "balance_after": 1}, sort=[("created_at", -1)])
        cash_balance = cash_latest.get("balance_after", 0) if cash_latest else 0
        
        bank_latest = await db.bank_ledger.find_one({}, {"_id": 0, "balance_after": 1}, sort=[("created_at", -1)])
        bank_balance = bank_latest.get("balance_after", 0) if bank_latest else 0
        
        receivable_comm = await db.commission_income_ledger.aggregate([
            {"$match": {"status": "pending"}},
            {"$group": {"_id": None, "total": {"$sum": "$net_commission"}}}
        ]).to_list(1)
        receivable_commission = receivable_comm[0].get("total", 0) if receivable_comm else 0
        
        total_prc_result = await db.users.aggregate([
            {"$group": {"_id": None, "total": {"$sum": "$prc_balance"}}}
        ]).to_list(1)
        total_prc = total_prc_result[0].get("total", 0) if total_prc_result else 0
        prc_liability_inr = total_prc / prc_per_inr
        
        deposit_payable_result = await db.deposit_ledger.aggregate([
            {"$match": {"status": "active"}},
            {"$group": {"_id": None, "total": {"$sum": "$deposit_amount"}}}
        ]).to_list(1)
        deposit_payable = deposit_payable_result[0].get("total", 0) if deposit_payable_result else 0
        
        pending_redeem_result = await db.redeem_payout_ledger.aggregate([
            {"$match": {"status": "pending"}},
            {"$group": {"_id": None, "total": {"$sum": "$amount_inr"}}}
        ]).to_list(1)
        pending_redeem = pending_redeem_result[0].get("total", 0) if pending_redeem_result else 0
        
        reserve_wallet = await db.company_wallets.find_one({"wallet_type": "reserve_fund"}, {"_id": 0})
        reserve_balance = reserve_wallet.get("balance", 0) if reserve_wallet else 0
        
        total_assets = cash_balance + bank_balance + receivable_commission
        total_liabilities = prc_liability_inr + deposit_payable + pending_redeem
        equity = total_assets - total_liabilities + reserve_balance
        
        balance_sheet = {
            "generated_at": datetime.now(timezone.utc).isoformat(),
            "assets": {
                "cash_balance": round(cash_balance, 2),
                "bank_balance": round(bank_balance, 2),
                "receivable_commission": round(receivable_commission, 2),
                "total_assets": round(total_assets, 2)
            },
            "liabilities": {
                "prc_liability_inr": round(prc_liability_inr, 2),
                "prc_in_system": round(total_prc, 2),
                "deposit_payable": round(deposit_payable, 2),
                "pending_redeem": round(pending_redeem, 2),
                "total_liabilities": round(total_liabilities, 2)
            },
            "equity": {
                "reserve_fund": round(reserve_balance, 2),
                "retained_earnings": round(equity - reserve_balance, 2),
                "total_equity": round(equity, 2)
            },
            "balance_check": {
                "assets": round(total_assets, 2),
                "liabilities_plus_equity": round(total_liabilities + equity, 2),
                "balanced": abs(total_assets - (total_liabilities + equity)) < 0.01
            }
        }
        
        return balance_sheet
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))

@api_router.get("/admin/ledger/master-summary")
async def get_master_ledger_summary():
    """Get master summary of all ledgers for quick overview"""
    try:
        settings = await db.settings.find_one({}, {"_id": 0, "accounting_settings": 1})
        prc_per_inr = settings.get("accounting_settings", {}).get("prc_per_inr", 10) if settings else 10
        
        ad_revenue_total = await db.ad_revenue_ledger.aggregate([{"$group": {"_id": None, "total": {"$sum": "$net_amount"}}}]).to_list(1)
        subscription_total = await db.subscription_income_ledger.aggregate([{"$match": {"status": "completed"}}, {"$group": {"_id": None, "total": {"$sum": "$amount"}}}]).to_list(1)
        commission_total = await db.commission_income_ledger.aggregate([{"$group": {"_id": None, "total": {"$sum": "$net_commission"}}}]).to_list(1)
        interest_total = await db.interest_income_ledger.aggregate([{"$group": {"_id": None, "total": {"$sum": "$interest_amount"}}}]).to_list(1)
        penalty_total = await db.penalty_income_ledger.aggregate([{"$group": {"_id": None, "total": {"$sum": "$equivalent_inr"}}}]).to_list(1)
        
        expense_total = await db.expense_ledger.aggregate([{"$group": {"_id": None, "total": {"$sum": "$amount"}}}]).to_list(1)
        redeem_total = await db.redeem_payout_ledger.aggregate([{"$match": {"status": "paid"}}, {"$group": {"_id": None, "total": {"$sum": "$amount_inr"}}}]).to_list(1)
        
        total_prc = await db.users.aggregate([{"$group": {"_id": None, "total": {"$sum": "$prc_balance"}}}]).to_list(1)
        
        total_income = (
            (ad_revenue_total[0].get("total", 0) if ad_revenue_total else 0) +
            (subscription_total[0].get("total", 0) if subscription_total else 0) +
            (commission_total[0].get("total", 0) if commission_total else 0) +
            (interest_total[0].get("total", 0) if interest_total else 0) +
            (penalty_total[0].get("total", 0) if penalty_total else 0)
        )
        
        total_expense = (
            (expense_total[0].get("total", 0) if expense_total else 0) +
            (redeem_total[0].get("total", 0) if redeem_total else 0)
        )
        
        prc_in_system = total_prc[0].get("total", 0) if total_prc else 0
        
        return {
            "income": {
                "ad_revenue": round(ad_revenue_total[0].get("total", 0) if ad_revenue_total else 0, 2),
                "subscription": round(subscription_total[0].get("total", 0) if subscription_total else 0, 2),
                "commission": round(commission_total[0].get("total", 0) if commission_total else 0, 2),
                "interest": round(interest_total[0].get("total", 0) if interest_total else 0, 2),
                "penalty_forfeit": round(penalty_total[0].get("total", 0) if penalty_total else 0, 2),
                "total": round(total_income, 2)
            },
            "expense": {
                "operational": round(expense_total[0].get("total", 0) if expense_total else 0, 2),
                "redeem_payouts": round(redeem_total[0].get("total", 0) if redeem_total else 0, 2),
                "total": round(total_expense, 2)
            },
            "net_profit_loss": round(total_income - total_expense, 2),
            "prc_stats": {
                "total_in_system": round(prc_in_system, 2),
                "inr_liability": round(prc_in_system / prc_per_inr, 2),
                "conversion_rate": prc_per_inr
            }
        }
    except Exception as e:
        raise HTTPException(status_code=500, detail=str(e))


# ========== LIVE PLATFORM STATS (PUBLIC - Google Policy Compliant) ==========

@api_router.get("/public/live-stats")
async def get_live_platform_stats():
    """
    Get live platform statistics for transparency panel
    Google Play Compliant - Shows activity stats, not revenue
    
    Returns:
    - Today PRC Earned (platform-wide)
    - Today PRC Burned (platform-wide)
    - Redeems Completed Today (count only)
    - Active Users (approximate)
    """
    try:
        today = datetime.now(timezone.utc).strftime("%Y-%m-%d")
        today_start = datetime.now(timezone.utc).replace(hour=0, minute=0, second=0, microsecond=0)
        
        today_prc_earned = 0
        today_prc_burned = 0
        redeems_today = 0
        
        # Try transactions collection first
        earned_pipeline = [
            {
                "$match": {
                    "transaction_type": {"$in": ["mining", "tap_game", "referral_bonus", "cashback", "prc_rain", "signup_bonus"]},
                    "created_at": {"$gte": today_start.isoformat()}
                }
            },
            {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
        ]
        earned_result = await db.transactions.aggregate(earned_pipeline).to_list(1)
        if earned_result:
            today_prc_earned = round(earned_result[0].get("total", 0), 2)
        
        # Also check wallet_transactions as fallback
        if today_prc_earned == 0:
            wallet_earned = await db.wallet_transactions.aggregate([
                {"$match": {"type": {"$in": ["credit", "mining", "tap", "referral", "bonus"]}, "created_at": {"$gte": today_start.isoformat()}}},
                {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
            ]).to_list(1)
            if wallet_earned:
                today_prc_earned = round(wallet_earned[0].get("total", 0), 2)
        
        # Also aggregate from user mining_history for today
        if today_prc_earned == 0:
            mining_today = await db.users.aggregate([
                {"$unwind": {"path": "$mining_history", "preserveNullAndEmptyArrays": False}},
                {"$match": {"mining_history.timestamp": {"$gte": today_start.isoformat()}}},
                {"$group": {"_id": None, "total": {"$sum": "$mining_history.amount"}}}
            ]).to_list(1)
            if mining_today:
                today_prc_earned = round(mining_today[0].get("total", 0), 2)
        
        # PRC Burned from transactions
        burned_pipeline = [
            {
                "$match": {
                    "transaction_type": {"$in": ["order", "redeem", "gift_voucher", "bill_payment", "burn", "expired"]},
                    "created_at": {"$gte": today_start.isoformat()}
                }
            },
            {"$group": {"_id": None, "total": {"$sum": {"$abs": "$amount"}}}}
        ]
        burned_result = await db.transactions.aggregate(burned_pipeline).to_list(1)
        if burned_result:
            today_prc_burned = round(burned_result[0].get("total", 0), 2)
        
        # Fallback: check wallet_transactions for debits
        if today_prc_burned == 0:
            wallet_burned = await db.wallet_transactions.aggregate([
                {"$match": {"type": {"$in": ["debit", "order", "redeem", "burn"]}, "created_at": {"$gte": today_start.isoformat()}}},
                {"$group": {"_id": None, "total": {"$sum": {"$abs": "$amount"}}}}
            ]).to_list(1)
            if wallet_burned:
                today_prc_burned = round(wallet_burned[0].get("total", 0), 2)
        
        # Redeems completed today (count only - no amounts for compliance)
        redeems_today = await db.transactions.count_documents({
            "transaction_type": {"$in": ["redeem", "gift_voucher", "bill_payment"]},
            "created_at": {"$gte": today_start.isoformat()}
        })
        
        # Fallback: check redeem_requests
        if redeems_today == 0:
            redeems_today = await db.redeem_requests.count_documents({
                "status": "completed",
                "created_at": {"$gte": today_start.isoformat()}
            })
        
        # Active users - users who logged in within last 7 days
        seven_days_ago = (datetime.now(timezone.utc) - timedelta(days=7)).isoformat()
        active_users = await db.users.count_documents({
            "last_login": {"$gte": seven_days_ago}
        })
        
        # Fallback: count all active users
        if active_users == 0:
            active_users = await db.users.count_documents({"is_active": True})
        
        # Get total PRC in system for reference
        total_prc_result = await db.users.aggregate([
            {"$group": {"_id": None, "total": {"$sum": "$prc_balance"}}}
        ]).to_list(1)
        total_prc = round(total_prc_result[0].get("total", 0), 2) if total_prc_result else 0
        
        # Get total products count
        total_products = await db.products.count_documents({"is_active": True})
        if total_products == 0:
            total_products = await db.products.count_documents({})
        
        # Get total PRC distributed (sum of all credits)
        total_distributed_result = await db.transactions.aggregate([
            {"$match": {"amount": {"$gt": 0}}},
            {"$group": {"_id": None, "total": {"$sum": "$amount"}}}
        ]).to_list(1)
        total_prc_distributed = round(total_distributed_result[0].get("total", 0), 2) if total_distributed_result else 0
        
        # Fallback from user totals
        if total_prc_distributed == 0:
            user_totals = await db.users.aggregate([
                {"$group": {"_id": None, "total": {"$sum": "$total_mined"}}}
            ]).to_list(1)
            total_prc_distributed = round(user_totals[0].get("total", 0), 2) if user_totals else 0
        
        return {
            "today_prc_earned": today_prc_earned,
            "today_prc_burned": today_prc_burned,
            "redeems_today": redeems_today,
            "active_users": active_users,
            "total_prc_in_system": total_prc,
            "total_prc_distributed": total_prc_distributed,
            "total_products": total_products,
            "timestamp": datetime.now(timezone.utc).isoformat()
        }
    except Exception as e:
        logging.error(f"Error fetching live stats: {e}")
        # Return safe fallback data
        return {
            "today_prc_earned": 0,
            "today_prc_burned": 0,
            "redeems_today": 0,
            "active_users": 0,
            "total_prc_in_system": 0,
            "timestamp": datetime.now(timezone.utc).isoformat()
        }


@api_router.get("/public/live-activity")
async def get_live_activity_feed():
    """
    Get live activity feed for social proof
    Google Play Compliant - No amounts, no earnings in INR
    
    Format: "User from {city} {action}"
    """
    try:
        # Get recent transactions (last 50) - include all activity types
        all_activity_types = [
            "mining", "tap_game", "order", "gift_voucher_request", "bill_payment_request",
            "prc_rain_gain", "prc_rain_loss", "cashback", "referral", "admin_credit"
        ]
        
        recent_transactions = await db.transactions.find(
            {"type": {"$in": all_activity_types}},
            {"_id": 0, "user_id": 1, "type": 1, "created_at": 1}
        ).sort("created_at", -1).limit(50).to_list(50)
        
        activities = []
        cities = ["Mumbai", "Pune", "Nashik", "Nagpur", "Thane", "Kolhapur", "Aurangabad", "Solapur", "Sangli", "Satara", "Amravati", "Nanded", "Akola", "Latur", "Jalgaon"]
        
        # Action mapping - key matches frontend actionTemplates
        action_map = {
            "mining": {"action": "mining", "text": "earned PRC via mining"},
            "tap_game": {"action": "tap_game", "text": "played tap game"},
            "order": {"action": "order", "text": "placed an order"},
            "gift_voucher_request": {"action": "voucher", "text": "claimed a gift voucher"},
            "bill_payment_request": {"action": "redeem", "text": "redeemed rewards"},
            "prc_rain_gain": {"action": "mining", "text": "earned PRC bonus"},
            "prc_rain_loss": {"action": "tap_game", "text": "participated in PRC rain"},
            "cashback": {"action": "redeem", "text": "earned cashback"},
            "referral": {"action": "mining", "text": "earned referral bonus"},
            "admin_credit": {"action": "mining", "text": "earned bonus PRC"}
        }
        
        import random
        for txn in recent_transactions[:15]:  # Show last 15 for more variety
            city = random.choice(cities)
            txn_type = txn.get("type", "mining")
            action_info = action_map.get(txn_type, {"action": "mining", "text": "earned rewards"})
            
            activities.append({
                "city": city,
                "action": action_info["action"],  # Key for frontend icon matching
                "text": action_info["text"],       # Display text
                "time_ago": _get_time_ago(txn.get("created_at"))
            })
        
        # If no real transactions, return empty to trigger frontend fallback
        if not activities:
            return {"activities": []}
        
        return {"activities": activities}
    except Exception as e:
        logging.error(f"Error fetching live activity: {e}")
        return {"activities": []}


def _get_time_ago(timestamp_str):
    """Helper to format time ago"""
    if not timestamp_str:
        return "just now"
    try:
        timestamp = datetime.fromisoformat(timestamp_str.replace('Z', '+00:00'))
        now = datetime.now(timezone.utc)
        diff = now - timestamp
        
        if diff.total_seconds() < 60:
            return "just now"
        elif diff.total_seconds() < 3600:
            return f"{int(diff.total_seconds() / 60)}m ago"
        elif diff.total_seconds() < 86400:
            return f"{int(diff.total_seconds() / 3600)}h ago"
        else:
            return f"{int(diff.total_seconds() / 86400)}d ago"
    except:
        return "recently"


@api_router.get("/user/insights/{uid}")
async def get_user_insights(uid: str):
    """
    Get personalized smart insights for user
    Google Play Compliant - No income predictions or money advice
    
    Returns contextual insights like:
    - "आज तुम्ही कालपेक्षा जास्त PRC कमावले"
    - "Recharge goal साठी फक्त 120 PRC बाकी"
    """
    try:
        user = await db.users.find_one({"uid": uid})
        if not user:
            return {"insights": []}
        
        insights = []
        today = datetime.now(timezone.utc).replace(hour=0, minute=0, second=0, microsecond=0)
        yesterday = today - timedelta(days=1)
        
        prc_balance = user.get("prc_balance", 0)
        total_mined = user.get("total_mined", 0)
        is_vip = user.get("membership_type") == "vip"
        mining_active = user.get("mining_active", False)
        
        # Calculate today's and yesterday's earnings from mining history
        mining_history = user.get("mining_history", [])
        today_earned = 0
        yesterday_earned = 0
        
        for entry in mining_history:
            try:
                entry_date = datetime.fromisoformat(entry.get("timestamp", "").replace('Z', '+00:00'))
                if entry_date >= today:
                    today_earned += entry.get("amount", 0)
                elif entry_date >= yesterday and entry_date < today:
                    yesterday_earned += entry.get("amount", 0)
            except:
                pass
        
        # Calculate mining streak
        mining_streak = 0
        if mining_history:
            sorted_history = sorted(mining_history, key=lambda x: x.get("timestamp", ""), reverse=True)
            current_date = today
            for entry in sorted_history:
                try:
                    entry_date = datetime.fromisoformat(entry.get("timestamp", "").replace('Z', '+00:00')).replace(hour=0, minute=0, second=0, microsecond=0)
                    if entry_date == current_date or entry_date == current_date - timedelta(days=1):
                        if entry_date != current_date:
                            current_date = entry_date
                        mining_streak += 1
                    else:
                        break
                except:
                    pass
        
        # Get referral count
        referral_count = await db.users.count_documents({"referred_by": user.get("referral_code")})
        
        # Generate insights based on user data
        
        # 1. Comparison insight (today vs yesterday)
        if today_earned > yesterday_earned and today_earned > 0:
            insights.append({
                "type": "positive",
                "icon": "trending",
                "message": "आज तुम्ही कालपेक्षा जास्त PRC कमावले! 🎉",
                "message_en": "You earned more PRC than yesterday! 🎉",
                "color": "green"
            })
        elif not mining_active and yesterday_earned > 0:
            insights.append({
                "type": "motivational",
                "icon": "zap",
                "message": "Mining सुरू करा, काल पेक्षा कमी PRC आहे! ⚡",
                "message_en": "Start mining, you have less PRC than yesterday! ⚡",
                "color": "orange"
            })
        
        # 2. Goal progress insight
        recharge_goal = 500  # PRC needed for basic recharge
        if prc_balance > 0 and prc_balance < recharge_goal:
            remaining = recharge_goal - prc_balance
            insights.append({
                "type": "goal",
                "icon": "target",
                "message": f"Recharge goal साठी फक्त {remaining:.0f} PRC बाकी! 🎯",
                "message_en": f"Only {remaining:.0f} PRC left for recharge goal! 🎯",
                "color": "blue"
            })
        
        # 3. Streak insight
        if mining_streak >= 3:
            insights.append({
                "type": "streak",
                "icon": "flame",
                "message": f"{mining_streak} दिवस सतत mining! Keep going! 🔥",
                "message_en": f"{mining_streak} day mining streak! Keep going! 🔥",
                "color": "orange"
            })
        
        # 4. VIP benefit insight
        if is_vip:
            insights.append({
                "type": "vip",
                "icon": "award",
                "message": "VIP म्हणून तुम्ही 2x PRC कमावत आहात! 👑",
                "message_en": "As VIP you are earning 2x PRC! 👑",
                "color": "yellow"
            })
        
        # 5. Referral tip
        if referral_count < 5:
            insights.append({
                "type": "tip",
                "icon": "sparkles",
                "message": "आणखी 1 referral = Mining speed boost! 👥",
                "message_en": "1 more referral = Mining speed boost! 👥",
                "color": "purple"
            })
        
        # 6. Close to voucher redemption
        voucher_threshold = 1000
        if prc_balance >= voucher_threshold - 200 and prc_balance < voucher_threshold:
            remaining = voucher_threshold - prc_balance
            insights.append({
                "type": "redeem",
                "icon": "gift",
                "message": f"अजून {remaining:.0f} PRC = ₹100 voucher! 💰",
                "message_en": f"{remaining:.0f} more PRC = ₹100 voucher! 💰",
                "color": "pink"
            })
        
        # 7. High performer insight
        if total_mined > 10000:
            insights.append({
                "type": "achievement",
                "icon": "award",
                "message": "तुम्ही top miners मध्ये आहात! ⭐",
                "message_en": "You are among top miners! ⭐",
                "color": "yellow"
            })
        
        # Default insight if none generated
        if not insights:
            insights.append({
                "type": "default",
                "icon": "zap",
                "message": "Mining सुरू करा आणि rewards मिळवा! ⚡",
                "message_en": "Start mining and earn rewards! ⚡",
                "color": "purple"
            })
        
        return {
            "insights": insights[:5],  # Return max 5 insights
            "stats": {
                "today_earned": round(today_earned, 2),
                "yesterday_earned": round(yesterday_earned, 2),
                "mining_streak": mining_streak,
                "referral_count": referral_count
            }
        }
    except Exception as e:
        logging.error(f"Error generating user insights: {e}")
        return {"insights": [], "stats": {}}


@api_router.get("/user/security/{uid}")
async def get_user_security_info(uid: str):
    """
    Get user security and trust information
    """
    try:
        user = await db.users.find_one({"uid": uid})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        # Calculate trust score
        trust_score = 50  # Base score
        if user.get("kyc_status") == "verified":
            trust_score += 20
        if user.get("email"):
            trust_score += 10
        if user.get("phone"):
            trust_score += 10
        if user.get("membership_type") == "vip":
            trust_score += 10
        
        return {
            "accountVerified": True,
            "prcProtected": True,
            "kycStatus": user.get("kyc_status", "pending"),
            "emailVerified": bool(user.get("email")),
            "phoneVerified": bool(user.get("phone")),
            "lastLogin": user.get("last_login"),
            "lastDevice": user.get("last_device", "Mobile Device"),
            "loginLocation": user.get("last_location", "India"),
            "trustScore": min(trust_score, 100)
        }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error fetching security info: {e}")
        raise HTTPException(status_code=500, detail=str(e))


@api_router.put("/user/settings/{uid}")
async def update_user_settings(uid: str, request: Request):
    """
    Update user control settings
    """
    try:
        data = await request.json()
        user = await db.users.find_one({"uid": uid})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        update_data = {}
        
        # Handle mining pause
        if "miningPaused" in data:
            update_data["mining_active"] = not data["miningPaused"]
        
        # Handle daily cap
        if "dailyPrcCap" in data:
            update_data["daily_prc_cap"] = data["dailyPrcCap"]
        
        # Handle utility only mode
        if "utilityOnlyMode" in data:
            update_data["utility_only_mode"] = data["utilityOnlyMode"]
        
        # Handle notifications
        if "notificationsEnabled" in data:
            update_data["notifications_enabled"] = data["notificationsEnabled"]
        
        if update_data:
            update_data["updated_at"] = datetime.now(timezone.utc).isoformat()
            await db.users.update_one({"uid": uid}, {"$set": update_data})
        
        return {"success": True, "updated": list(update_data.keys())}
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error updating user settings: {e}")
        raise HTTPException(status_code=500, detail=str(e))


@api_router.get("/user/statement/{uid}")
async def get_user_statement(uid: str, format: str = "csv", period: str = "month"):
    """
    Generate PRC statement for user
    Google Play Compliant - Header includes disclaimer
    """
    try:
        user = await db.users.find_one({"uid": uid})
        if not user:
            raise HTTPException(status_code=404, detail="User not found")
        
        # Calculate date range
        now = datetime.now(timezone.utc)
        if period == "week":
            start_date = now - timedelta(days=7)
        elif period == "month":
            start_date = now - timedelta(days=30)
        elif period == "quarter":
            start_date = now - timedelta(days=90)
        else:  # year
            start_date = now - timedelta(days=365)
        
        # Get transactions
        transactions = await db.transactions.find({
            "user_id": uid,
            "created_at": {"$gte": start_date.isoformat()}
        }).sort("created_at", -1).to_list(1000)
        
        # Also check mining history
        mining_history = user.get("mining_history", [])
        
        if format == "csv":
            # Generate CSV
            lines = [
                "Reward Points Statement – Not a Financial Investment",
                "",
                f"User: {user.get('name', 'User')}",
                f"Email: {user.get('email', 'N/A')}",
                f"Period: {start_date.strftime('%Y-%m-%d')} to {now.strftime('%Y-%m-%d')}",
                f"Current Balance: {user.get('prc_balance', 0)} PRC",
                "",
                "Date,Type,Description,PRC Amount"
            ]
            
            for txn in transactions:
                date = txn.get("created_at", "")[:10]
                txn_type = txn.get("transaction_type", "unknown")
                desc = txn.get("description", txn_type)
                amount = txn.get("amount", 0)
                lines.append(f"{date},{txn_type},{desc},{amount}")
            
            for entry in mining_history:
                try:
                    entry_date = datetime.fromisoformat(entry.get("timestamp", "").replace('Z', '+00:00'))
                    if entry_date >= start_date:
                        date = entry_date.strftime("%Y-%m-%d")
                        amount = entry.get("amount", 0)
                        lines.append(f"{date},mining,Mining Reward,{amount}")
                except:
                    pass
            
            content = "\n".join(lines)
            
            from fastapi.responses import Response
            return Response(
                content=content,
                media_type="text/csv",
                headers={"Content-Disposition": f"attachment; filename=prc_statement_{period}.csv"}
            )
        else:
            # Return JSON for PDF generation on frontend
            return {
                "user_name": user.get("name", "User"),
                "email": user.get("email", "N/A"),
                "period_start": start_date.isoformat(),
                "period_end": now.isoformat(),
                "current_balance": user.get("prc_balance", 0),
                "transactions": [
                    {
                        "date": txn.get("created_at", "")[:10],
                        "type": txn.get("transaction_type", "unknown"),
                        "description": txn.get("description", ""),
                        "amount": txn.get("amount", 0)
                    }
                    for txn in transactions
                ],
                "disclaimer": "Reward Points Statement – Not a Financial Investment"
            }
    except HTTPException:
        raise
    except Exception as e:
        logging.error(f"Error generating statement: {e}")
        raise HTTPException(status_code=500, detail=str(e))


